259	  constructor(private opts: AcpClientOptions) {
260	    super();
261	    // On Windows, CreateProcess can't launch .bat/.cmd/.ps1 directly, so we
262	    // need a shell for those. Everything else (node, npx.exe, a real .exe)
263	    // can be spawned without a shell — which avoids Node's DEP0190 warning
264	    // about passing args alongside `shell: true` and also sidesteps any
265	    // shell-quoting surprises in the args array.
266	    const needsShell = AcpClient.commandNeedsShell(opts.command);
267	    if (needsShell) {
268	      // When shell is required, build a single quoted command string and
269	      // pass empty args — that's the API shape Node wants post-DEP0190.
270	      const cmdLine = [opts.command, ...opts.args]
271	        .map(AcpClient.quoteForShell)
272	        .join(" ");
273	      this.proc = spawn(cmdLine, [], {
274	        cwd: opts.cwd,
275	        env: buildSpawnEnv(opts.env),
276	        stdio: ["pipe", "pipe", "pipe"],
277	        shell: true,
278	      });
279	    } else {
280	      this.proc = spawn(opts.command, opts.args, {
281	        cwd: opts.cwd,
282	        env: buildSpawnEnv(opts.env),
283	        stdio: ["pipe", "pipe", "pipe"],
284	      });
285	    }
286	
287	    // Keep stdout as Buffer so LSP byte-length framing works correctly.
288	    this.proc.stderr.setEncoding("utf8");
289	
290	    this.proc.stdout.on("data", (chunk: Buffer) => this.onStdout(chunk));
291	    this.proc.stderr.on("data", (chunk: string) => this.emit("stderr", chunk));
292	    this.proc.on("exit", (code) => {
293	      this.closed = true;
294	      for (const { reject } of this.pending.values()) {
295	        reject(new Error(`ACP agent exited with code ${code}`));
296	      }
297	      this.pending.clear();
298	      this.emit("exit", code);
299	    });
300	    this.proc.on("error", (err) => {
301	      this.emit("stderr", `spawn error: ${err.message}\n`);
302	    });
303	  }
